  1	import React, { FC, useCallback, useEffect, useState } from 'react';
  2	
  3	import SelectToggle from '@kubevirt-utils/components/toggles/SelectToggle';
  4	import { t } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import usePermissions from '@kubevirt-utils/hooks/usePermissions/usePermissions';
  6	import useCanCreateBootableVolume from '@kubevirt-utils/resources/bootableresources/hooks/useCanCreateBootableVolume';
  7	import { Divider, FormGroup, SelectGroup } from '@patternfly/react-core';
  8	import { Select, SelectOption } from '@patternfly/react-core';
  9	
 10	import { DROPDOWN_FORM_SELECTION, optionsValueLabelMapper } from '../../utils/constants';
 11	
 12	type SourceTypeSelectionProps = {
 13	  formSelection: DROPDOWN_FORM_SELECTION;
 14	  namespace: string;
 15	  setFormSelection: (value: DROPDOWN_FORM_SELECTION) => void;
 16	};
 17	
 18	const SourceTypeSelection: FC<SourceTypeSelectionProps> = ({
 19	  formSelection,
 20	  namespace,
 21	  setFormSelection,
 22	}) => {
 23	  const [isOpen, setIsOpen] = useState(false);
 24	  const { canCreateDS, canCreatePVC, canCreateSnapshots, loading } =
 25	    useCanCreateBootableVolume(namespace);
 26	  const { capabilitiesData, isLoading: permissionsLoading } = usePermissions();
 27	  const canUploadImage = capabilitiesData.uploadImage.allowed && canCreatePVC;
 28	
 29	  const onSelect = useCallback(
 30	    (event, value) => {
 31	      event.preventDefault();
 32	      setFormSelection(value);
 33	      setIsOpen(false);
 34	    },
 35	    [setFormSelection],
 36	  );
 37	
 38	  useEffect(() => {
 39	    if (!permissionsLoading && !loading) {
 40	      setFormSelection(
 41	        !canUploadImage
 42	          ? DROPDOWN_FORM_SELECTION.USE_REGISTRY
 43	          : DROPDOWN_FORM_SELECTION.UPLOAD_VOLUME,
 44	      );
 45	    }
 46	  }, [canUploadImage, permissionsLoading, loading, setFormSelection]);
 47	
 48	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
 49	
 50	  return (
 51	    <FormGroup fieldId="source-type" label={t('Source type')}>
 52	      <Select
 53	        toggle={SelectToggle({
 54	          'data-test-id': 'source-type-select',
 55	          isExpanded: isOpen,
 56	          isFullWidth: true,
 57	          onClick: onToggle,
 58	          selected: optionsValueLabelMapper[formSelection],
 59	        })}
 60	        isOpen={isOpen}
 61	        onOpenChange={(open: boolean) => setIsOpen(open)}
 62	        onSelect={onSelect}
 63	        selected={formSelection}
 64	      >
 65	        <SelectGroup label={t('Upload new')}>
 66	          <SelectOption
 67	            isDisabled={!canUploadImage}
 68	            value={DROPDOWN_FORM_SELECTION.UPLOAD_VOLUME}
 69	            {...(!canUploadImage && {
 70	              description: t("You don't have permission to perform this action"),
 71	            })}
 72	            data-test-id="upload-volume"
 73	          >
 74	            {optionsValueLabelMapper[DROPDOWN_FORM_SELECTION.UPLOAD_VOLUME]}
 75	          </SelectOption>
 76	        </SelectGroup>
 77	        <Divider />
 78	        <SelectGroup label={t('Use existing')}>
 79	          <SelectOption
 80	            data-test-id="use-existing-volume"
 81	            description={t('Use volume already available on the cluster')}
 82	            isDisabled={!canCreatePVC}
 83	            value={DROPDOWN_FORM_SELECTION.USE_EXISTING_PVC}
 84	          >
 85	            {optionsValueLabelMapper[DROPDOWN_FORM_SELECTION.USE_EXISTING_PVC]}
 86	          </SelectOption>
 87	          <SelectOption
 88	            data-test-id="use-snapshot"
 89	            isDisabled={!canCreateSnapshots}
 90	            value={DROPDOWN_FORM_SELECTION.USE_SNAPSHOT}
 91	          >
 92	            {optionsValueLabelMapper[DROPDOWN_FORM_SELECTION.USE_SNAPSHOT]}
 93	          </SelectOption>
 94	        </SelectGroup>
 95	        <Divider />
 96	        <SelectGroup label={t('Import from')}>
 97	          <SelectOption
 98	            data-test-id="use-registry"
 99	            description={t('Content from container registry')}
100	            isDisabled={!canCreateDS}
101	            value={DROPDOWN_FORM_SELECTION.USE_REGISTRY}
102	          >
103	            {optionsValueLabelMapper[DROPDOWN_FORM_SELECTION.USE_REGISTRY]}
104	          </SelectOption>
105	        </SelectGroup>
106	      </Select>
107	    </FormGroup>
108	  );
109	};
110	
111	export default SourceTypeSelection;

